const domain = ($('Get keywords').item.json.Domain || '').toLowerCase().replace(/^https?:\/\//,'').replace(/^www\./,'').replace(/\/$/,'');
const results = $input.first().json.organic_results || [];
let rank = 0;
for (const r of results) {
  const link = (r.link || '').toLowerCase();
  if (domain && link.includes(domain)) { rank = r.position || 0; break; }
}
return [{ json: {
  Keyword: $('Get keywords').item.json.Keyword,
  Domain: $('Get keywords').item.json.Domain,
  'Old Rank': $('Get keywords').item.json['Last Rank'] || '',
  'Last Rank': rank,
} }];
